using System.ComponentModel;
using System.Net;
using System.Text.Json;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
var modelName = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

// ---------------------------------------------------------------------------
// Build the AI chat client with automatic function-invocation middleware
// ---------------------------------------------------------------------------
IChatClient innerClient =
    new OpenAIChatClient(new OpenAI.OpenAIClient(apiKey).GetChatClient(modelName));

var client = new FunctionInvokingChatClient(innerClient);
client.MaximumIterationsPerRequest = 15;

// ---------------------------------------------------------------------------
// Register tools
// ---------------------------------------------------------------------------
var notepad = new Notepad();
var webSearch = new WebSearch();

var chatOptions = new ChatOptions
{
    Tools =
    [
        AIFunctionFactory.Create(webSearch.SearchAsync),
        AIFunctionFactory.Create(webSearch.FetchPageAsync),
        AIFunctionFactory.Create(notepad.AddNote),
        AIFunctionFactory.Create(notepad.GetNotes),
    ]
};

// ---------------------------------------------------------------------------
// Prompt the user
// ---------------------------------------------------------------------------
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided – exiting.");
    return;
}

Console.WriteLine($"\n📚  Researching: {topic}\n");

// ---------------------------------------------------------------------------
// Run the agent
// ---------------------------------------------------------------------------
List<ChatMessage> messages =
[
    new(ChatRole.System, """
        You are a thorough research agent. Given a topic you must:

        1. Search the web for relevant information (try 2-3 varied queries).
        2. Fetch the most promising pages to read their content.
        3. Use the note-taking tool to record every key finding as you go.
        4. After gathering enough information, review your notes.
        5. Produce a well-structured summary with sections and citations.

        Be methodical: search, read, note, repeat until you have good coverage.
        """),
    new(ChatRole.User,
        $"Please research the following topic and provide a comprehensive summary:\n\n{topic}"),
];

var response = await client.GetResponseAsync(messages, chatOptions);

Console.WriteLine("\n════════════════════════════════════════");
Console.WriteLine("  RESEARCH SUMMARY");
Console.WriteLine("════════════════════════════════════════\n");
Console.WriteLine(response.Text);

if (notepad.Count > 0)
{
    Console.WriteLine($"\n── {notepad.Count} research note(s) were collected. ──");
}

// ═══════════════════════════════════════════════════════════════════════════
// Tool implementations
// ═══════════════════════════════════════════════════════════════════════════

/// <summary>Simple in-memory notepad the agent uses to organise findings.</summary>
public sealed class Notepad
{
    private readonly List<string> _notes = [];
    public int Count => _notes.Count;

    [Description("Save a research note so you can refer to it later.")]
    public string AddNote([Description("The text of the note to save")] string note)
    {
        _notes.Add(note);
        var preview = note.Length > 90 ? note[..90] + "…" : note;
        Console.WriteLine($"  📝 Note #{_notes.Count}: {preview}");
        return $"Note #{_notes.Count} saved.";
    }

    [Description("Retrieve all research notes collected so far.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes yet.";

        return string.Join('\n', _notes.Select((n, i) => $"[{i + 1}] {n}"));
    }
}

/// <summary>Web search and page-fetching tools backed by DuckDuckGo HTML.</summary>
public sealed class WebSearch
{
    private static readonly HttpClient Http = new()
    {
        DefaultRequestHeaders = { { "User-Agent", "ResearchAgent/1.0" } },
        Timeout = TimeSpan.FromSeconds(20),
    };

    [Description("Search the web for a query. Returns up to 5 results with titles and URLs.")]
    public async Task<string> SearchAsync(
        [Description("The search query string")] string query)
    {
        Console.WriteLine($"  🔍 Searching: \"{query}\"");
        try
        {
            var encoded = WebUtility.UrlEncode(query);
            var html = await Http.GetStringAsync(
                $"https://html.duckduckgo.com/html/?q={encoded}");

            var results = Regex.Matches(html,
                    @"<a rel=""nofollow"" class=""result__a"" href=""(?<url>[^""]+)"">(?<title>.+?)</a>")
                .Cast<Match>()
                .Take(5)
                .Select(m =>
                {
                    var rawUrl = m.Groups["url"].Value;
                    var uddg = Regex.Match(rawUrl, @"uddg=([^&]+)");
                    var url = uddg.Success
                        ? WebUtility.UrlDecode(uddg.Groups[1].Value)
                        : rawUrl;
                    return new
                    {
                        Title = StripHtml(m.Groups["title"].Value),
                        Url = url,
                    };
                })
                .Where(r => !string.IsNullOrWhiteSpace(r.Url))
                .ToList();

            if (results.Count == 0)
                return "No results found. Try rephrasing the query.";

            return JsonSerializer.Serialize(results,
                new JsonSerializerOptions { WriteIndented = true });
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Fetch and return the text content of a web page (max ~3 000 chars).")]
    public async Task<string> FetchPageAsync(
        [Description("The URL to fetch")] string url)
    {
        Console.WriteLine($"  🌐 Fetching: {url}");
        try
        {
            var html = await Http.GetStringAsync(url);
            var text = StripHtml(html);
            text = Regex.Replace(text, @"\s+", " ").Trim();
            return text.Length > 3_000 ? text[..3_000] + " …" : text;
        }
        catch (Exception ex)
        {
            return $"Fetch failed: {ex.Message}";
        }
    }

    private static string StripHtml(string html)
    {
        html = Regex.Replace(html, @"<script[^>]*>[\s\S]*?</script>", " ");
        html = Regex.Replace(html, @"<style[^>]*>[\s\S]*?</style>", " ");
        html = Regex.Replace(html, @"<[^>]+>", " ");
        return WebUtility.HtmlDecode(html);
    }
}

